// Show vishaya \(topic\) information popup
function showVishayaInfo\(topic\) {
    if \(!topic || !topic.id\) return;

    // Create popup overlay if it doesn't exist
    let popup = document.getElementById\('vishayaPopup'\);
    if \(!popup\) {
        popup = document.createElement\('div'\);
        popup.id = 'vishayaPopup';
        popup.className = 'vishaya-popup-overlay';
        document.body.appendChild\(popup\);
    }

    const topicText = currentLanguage !== 'sa' ? 
                      transliterateText\(topic.sutra_text, currentLanguage\) : 
                      topic.sutra_text;

    const vishayaLabel = currentLanguage !== 'sa' ? 
                         transliterateText\('विषयः', currentLanguage\) : 
                         'विषयः';

    // Get vishaya details from JSON
    let details = {};
    if \(adhikaranaDetails && adhikaranaDetails[topic.id]\) {
        details = adhikaranaDetails[topic.id];
    }

    console.log\('Vishaya ID:', topic.id\);
    console.log\('Vishaya details:', details\);

    // Build details sections
    let detailsHTML = '';

    // Fields to skip
    const metadataFields = ['id', 'topic'];

    // Display all custom fields
    for \(const [fieldKey, fieldValue] of Object.entries\(details\)\) {
        if \(metadataFields.includes\(fieldKey\)\) continue;
        if \(typeof fieldValue !== 'string'\) continue;

        // Transliterate field label and value based on current language
        const fieldLabel = currentLanguage !== 'sa' ? transliterateText\(fieldKey, currentLanguage\) : fieldKey;
        const transliteratedValue = currentLanguage !== 'sa' ? transliterateText\(fieldValue, currentLanguage\) : fieldValue;

        detailsHTML += `<div class="vishaya-detail-section">
            <strong>${fieldLabel}:</strong>
            ${transliteratedValue}
        </div>`;
    }

    // If no details found, show a message
    if \(!detailsHTML\) {
        detailsHTML = `<div class="vishaya-detail-section">
            <em>Details for this topic will be added soon.</em>
        </div>`;
    }

    popup.innerHTML = `
        <div class="vishaya-popup-content">
            <div class="vishaya-popup-header">
                <h3>${vishayaLabel}</h3>
                <button class="vishaya-popup-close" onclick="closeVishayaPopup\(\)">&times;</button>
            </div>
            <div class="vishaya-popup-body">
                <div class="vishaya-name">${topicText}</div>
                <h4>Topic Details:</h4>
                ${detailsHTML}
            </div>
        </div>
    `;

    popup.style.display = 'flex';

    // Close popup when clicking outside
    popup.addEventListener\('click', \(e\) => {
        if \(e.target === popup\) {
            closeVishayaPopup\(\);
        }
    }\);
}

function closeVishayaPopup\(\) {
    const popup = document.getElementById\('vishayaPopup'\);
    if \(popup\) {
        popup.style.display = 'none';
    }
}

// Make functions globally available
window.showVishayaInfo = showVishayaInfo;
window.closeVishayaPopup = closeVishayaPopup;
JSCODE)
